      if (!query) {
        return this.recentRecords;
      }
      return this.recentRecords.filter(record => {
        const info = record.personalInformation || {};
        const operation = record.operationDetails || {};
        return [info.firstName, info.middleName, info.lastName, info.alias, operation.operationName].filter(Boolean).some(value => value.toLowerCase().includes(query));
      });
    },
    bubbleRecords() {
      if (!this.selectedBubbleRecordId) {
        return this.recentRecords.slice(0, 7);
      }
      const selectedRecord = this.recentRecords.find(record => record._id === this.selectedBubbleRecordId);
      const remainingRecords = this.recentRecords.filter(record => record._id !== this.selectedBubbleRecordId);
      return [selectedRecord, ...remainingRecords].filter(Boolean).slice(0, 7);
    }
