        this.recentRecords = Array.isArray(response.data) ? response.data : [];
        this.selectedBubbleRecordId = this.selectedBubbleRecordId && this.recentRecords.some(record => record._id === this.selectedBubbleRecordId) ? this.selectedBubbleRecordId : this.recentRecords[0]?._id || "";
        this.initializeBubblePositions();
      } catch (error) {
        this.recordsError = error.response?.data?.message || "Unable to load recent registrations.";
      } finally {
        this.isLoadingRecords = false;
      }
    },
    formatRecordName(record) {
      const info = record.personalInformation || {};
      return [info.firstName, info.middleName, info.lastName].filter(Boolean).join(" ");
