    getRecordInitials(record) {
      const info = record.personalInformation || {};
      return [info.firstName, info.lastName].filter(Boolean).map(value => value.charAt(0)).join("").slice(0, 2) || "NA";
    },
    formatRecordMeta(record) {
      const info = record.personalInformation || {};
      const operation = record.operationDetails || {};
      const createdAt = record.createdAt ? new Date(record.createdAt).toLocaleDateString() : "No date";
      return [info.alias ? `Alias: ${info.alias}` : null, operation.operationName || null, createdAt].filter(Boolean).join(" | ");
    },
    getBubbleSubtitle(record) {
      const operation = record.operationDetails || {};
      return operation.operationName || "Recent registration";
    },
    getBubbleStyle(index) {
      const bubble = this.getBubbleConfig(index);
      return {
        top: bubble.top,
        left: bubble.left,
        width: `${bubble.size}px`,
        height: `${bubble.size}px`
      };
