        size: 114
      }, {
        top: "72%",
        left: "26%",
        size: 96
      }, {
        top: "28%",
        left: "82%",
        size: 90
      }];
      const fallback = {
        top: "35%",
        left: "40%",
        size: 110
      };
      if (this.selectedBubbleRecordId && index === 0) {
        return focusLayout;
      }
      return layouts[index] || fallback;
