        return;
      }
      event.preventDefault();
      const boardRect = board.getBoundingClientRect();
      this.activeBubbleDrag = {
        id: record._id,
        size: position.size,
        offsetX: event.clientX - boardRect.left - parseFloat(position.left) / 100 * boardRect.width,
        offsetY: event.clientY - boardRect.top - parseFloat(position.top) / 100 * boardRect.height
